import json
import os
import boto3
from botocore.exceptions import ClientError

sns_client = boto3.client("sns")

DEFAULT_TOPIC_ARN = os.environ.get("DEFAULT_TOPIC_ARN", "")


def _build_message(event):
    notification_type = event.get("notification_type", "default")
    content = event.get("message", event.get("content", ""))

    if isinstance(content, dict):
        content = json.dumps(content)

    if notification_type == "email":
        subject = event.get("subject", "Notification")
        return {
            "Message": content,
            "Subject": subject
        }
    elif notification_type == "sms":
        return {
            "Message": content
        }
    elif notification_type == "push":
        title = event.get("title", "Notification")
        payload = {
            "default": content,
            "GCM": json.dumps({
                "notification": {
                    "title": title,
                    "body": content
                }
            }),
            "APNS": json.dumps({
                "aps": {
                    "alert": {
                        "title": title,
                        "body": content
                    },
                    "sound": "default"
                }
            }),
            "APNS_SANDBOX": json.dumps({
                "aps": {
                    "alert": {
                        "title": title,
                        "body": content
                    },
                    "sound": "default"
                }
            })
        }
        return {
            "Message": json.dumps(payload),
            "MessageStructure": "json"
        }
    else:
        return {
            "Message": content
        }


def lambda_handler(event, context):
    topic_arn = event.get("topic_arn") or DEFAULT_TOPIC_ARN
    if not topic_arn:
        return {
            "statusCode": 400,
            "body": json.dumps({"error": "Missing topic_arn"})
        }

    try:
        publish_args = _build_message(event)
        publish_args["TopicArn"] = topic_arn

        response = sns_client.publish(**publish_args)

        return {
            "statusCode": 200,
            "body": json.dumps({
                "message": "Notification published successfully",
                "message_id": response.get("MessageId"),
                "topic_arn": topic_arn
            })
        }
    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps({
                "error": "Failed to publish notification",
                "details": str(e)
            })
        }
    except Exception as e:
        return {
            "statusCode": 500,
            "body": json.dumps({
                "error": "Unexpected error",
                "details": str(e)
            })
        }